// QDrant DB Collection
const collection = $env.QDRANT_COLLECTION;

return {
  "collection": collection
};

// Input Data
var data = $input.first().json.data;

// QDrant DB Collection
const collection = $env.QDRANT_COLLECTION;

// Loop through data array
const results = [];

for (const item of data) {
  // Process each item
  results.push({
    id: item.id,
    topic: item.topic,
    question: item.question,
    answer: item.answer,
    embeddingText: `[${item.topic}] ${item.question}`,
    collection: `${collection}`
  });
}

return results;

// QDrant DB Collection
const collection = $env.QDRANT_COLLECTION;

return {
  "collection": collection
};

